import SwiftUI
import LocalAuthentication

class AuthenticationManager: ObservableObject {
    @Published var isAuthenticated: Bool {
        didSet {
            UserDefaults.standard.set(isAuthenticated, forKey: "isAuthenticated")
        }
    }
    @Published var authenticationError: LAError?

    init() {
        self.isAuthenticated = UserDefaults.standard.bool(forKey: "isAuthenticated")
    }

    func authenticateWithBiometrics() {
        let context = LAContext()
        var error: NSError?

        if context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) {
            let reason = "Authenticate to access your account."

            context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason) { success, authenticationError in
                DispatchQueue.main.async {
                    if success {
                        self.isAuthenticated = true
                        self.authenticationError = nil
                    } else {
                        self.isAuthenticated = false
                        self.authenticationError = authenticationError as? LAError
                        print("Biometric authentication failed: \(authenticationError?.localizedDescription ?? "Unknown error")")
                    }
                }
            }
        } else {
            DispatchQueue.main.async {
                self.isAuthenticated = false
                self.authenticationError = error as? LAError
                print("Biometrics not available: \(error?.localizedDescription ?? "Unknown error")")
            }
        }
    }

    func resetAuthentication() {
        isAuthenticated = false
        authenticationError = nil
    }
}

struct ContentView: View {
    @EnvironmentObject var authManager: AuthenticationManager

    var body: some View {
        Group {
            if authManager.isAuthenticated {
                HomeView()
            } else {
                LoginView()
            }
        }
    }
}

struct LoginView: View {
    @EnvironmentObject var authManager: AuthenticationManager
    @State private var username = ""
    @State private var password = ""
    @State private var showingPasswordLogin = false

    var body: some View {
        NavigationView {
            VStack {
                Spacer()

                Text("Welcome Back")
                    .font(.largeTitle)
                    .padding(.bottom, 50)

                if !showingPasswordLogin {
                    Button(action: {
                        authManager.authenticateWithBiometrics()
                    }) {
                        HStack {
                            Image(systemName: authManager.authenticationError?.code == .biometryNotAvailable ? "lock.fill" : (authManager.authenticationError?.code == .biometryNotEnrolled ? "faceid" : "touchid"))
                                .font(.title)
                            Text(authManager.authenticationError?.code == .biometryNotAvailable ? "Biometrics Unavailable" : (authManager.authenticationError?.code == .biometryNotEnrolled ? "Set Up Biometrics" : "Authenticate with Biometrics"))
                                .font(.headline)
                        }
                        .padding()
                        .frame(maxWidth: .infinity)
                        .background(Color.blue)
                        .foregroundColor(.white)
                        .cornerRadius(10)
                    }
                    .padding(.horizontal)
                    .disabled(authManager.authenticationError?.code == .biometryNotAvailable || authManager.authenticationError?.code == .biometryNotEnrolled)

                    if let error = authManager.authenticationError {
                        Text(errorMessage(for: error))
                            .foregroundColor(.red)
                            .padding(.top, 5)
                            .multilineTextAlignment(.center)
                    }

                    Button("Use Password Instead") {
                        showingPasswordLogin = true
                        authManager.authenticationError = nil // Clear error when switching to password
                    }
                    .padding(.top, 20)
                } else {
                    TextField("Username", text: $username)
                        .textFieldStyle(RoundedBorderTextFieldStyle())
                        .padding(.horizontal)
                        .autocapitalization(.none)
                        .disableAutocorrection(true)

                    SecureField("Password", text: $password)
                        .textFieldStyle(RoundedBorderTextFieldStyle())
                        .padding(.horizontal)
                        .padding(.top, 10)

                    Button("Login") {
                        // Simulate password login
                        if username == "user" && password == "password" {
                            authManager.isAuthenticated = true
                        } else {
                            // Show error for invalid credentials
                            print("Invalid credentials")
                        }
                    }
                    .padding()
                    .frame(maxWidth: .infinity)
                    .background(Color.green)
                    .foregroundColor(.white)
                    .cornerRadius(10)
                    .padding(.horizontal)
                    .padding(.top, 20)

                    Button("Back to Biometrics") {
                        showingPasswordLogin = false
                        username = ""
                        password = ""
                    }
                    .padding(.top, 20)
                }

                Spacer()
            }
            .navigationTitle("Login")
            .navigationBarHidden(true)
        }
        .onAppear {
            if !authManager.isAuthenticated {
                authManager.authenticateWithBiometrics()
            }
        }
    }

    private func errorMessage(for error: LAError) -> String {
        switch error.code {
        case .userCancel:
            return "Authentication was cancelled by the user."
        case .userFallback:
            return "User chose to enter password."
        case .systemCancel:
            return "Authentication was cancelled by the system."
        case .passcodeNotSet:
            return "Passcode is not set on your device."
        case .biometryNotAvailable:
            return "Biometric authentication is not available on this device."
        case .biometryNotEnrolled:
            return "No biometrics enrolled. Please set up Face ID or Touch ID in Settings."
        case .biometryLockout:
            return "Biometrics locked. Please use your passcode."
        case .appCancel:
            return "Authentication was cancelled by the application."
        case .invalidContext:
            return "The context is invalid."
        default:
            return "Authentication failed: \(error.localizedDescription)"
        }
    }
}

